import React from "react";
import { useParams, useNavigate } from "react-router-dom";
import Button from "react-bootstrap/Button";
import Container from "react-bootstrap/Container";
import Row from "react-bootstrap/Row";
import Col from "react-bootstrap/Col";

function WatchVideo() {
  const { videoId } = useParams();
  const navigate = useNavigate();

  return (
    <Container>
      <Row className="mt-4">
        {/* Left Column for Video */}
        <Col md={9} xs={12} lg={9}>
          <Container className="text-center">
            <Button variant="secondary" onClick={() => navigate(-1)}>
              ⬅ Back
            </Button>
            <h2 className="mt-3">Watch Video</h2>
            <iframe
              width="100%" // Set to 100% to take full width of the Col
              height="450"
              src={`https://www.youtube.com/embed/${videoId}?autoplay=1`}
              title="YouTube Video Player"
              frameBorder="0"
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
              allowFullScreen
            ></iframe>
          </Container>
        </Col>

        {/* Right Column for Notes */}
        <Col md={5} xs={12} lg={3} className="d-flex flex-column align-items-start">
          <div className="notes mt-4">
            <label htmlFor="notesTextarea">Add your notes:</label>
            <textarea
              id="notesTextarea"
              rows="10"
              className="form-control mt-3 textarea-custom"
              placeholder="Write your notes here..."
            ></textarea>
          </div>
        </Col>
      </Row>
    </Container>
  );
}

export default WatchVideo;
